173	function TopBarModePills({
174	  tablistId,
175	  mode,
176	  onModeChange,
177	}: {
178	  tablistId: string;
179	  mode: WorkspaceMode;
180	  onModeChange: (next: WorkspaceMode) => void;
181	}): JSX.Element {
182	  const { t } = useTranslation();
183	  const tabRefs = useRef<Map<WorkspaceMode, HTMLButtonElement>>(new Map());
184	  const setTabRef = useCallback(
185	    (id: WorkspaceMode) => (el: HTMLButtonElement | null) => {
186	      if (el) tabRefs.current.set(id, el);
187	      else tabRefs.current.delete(id);
188	    },
189	    [],
190	  );
191	
192	  const handleKey = useCallback(
193	    (event: KeyboardEvent<HTMLDivElement>) => {
194	      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
195	      const idx = WORKSPACE_MODES.findIndex((m) => m.id === mode);
196	      if (idx < 0) return;
197	      const delta = event.key === 'ArrowRight' ? 1 : -1;
198	      const next = WORKSPACE_MODES[(idx + delta + WORKSPACE_MODES.length) % WORKSPACE_MODES.length];
199	      event.preventDefault();
200	      onModeChange(next.id);
201	      tabRefs.current.get(next.id)?.focus();
202	    },
