232	            ].join(' ')}
233	            style={active ? { boxShadow: 'inset 0 -2px 0 0 var(--color-accent)' } : undefined}
234	          >
235	            {modeLabel}
236	            <span aria-hidden="true" className="ml-1.5 text-[10px] tabular-nums opacity-40">
237	              {m.hotkey}
238	            </span>
239	          </button>
240	        );
241	      })}
242	    </div>
243	  );
244	}
