246	function TopBarRight({
247	  theme,
248	  onThemeToggle,
249	  onCommandPalette,
250	  onSettings,
251	  collaboratorsCount,
252	  onCollaboratorsClick,
253	  avatarInitials,
254	  peers,
255	  perspectiveOptions,
256	  perspectiveValue,
257	  onPerspectiveChange,
258	  planStyleOptions,
259	  planStyleValue,
260	  onPlanStyleChange,
261	}: {
262	  theme: 'light' | 'dark';
263	  onThemeToggle?: () => void;
264	  onCommandPalette?: () => void;
265	  onSettings?: () => void;
266	  collaboratorsCount?: number;
267	  onCollaboratorsClick?: () => void;
268	  avatarInitials?: string;
269	  peers?: Array<{ name?: string; color?: string }>;
270	  perspectiveOptions?: TopBarSelectOption[];
271	  perspectiveValue?: string;
272	  onPerspectiveChange?: (id: string) => void;
273	  planStyleOptions?: TopBarSelectOption[];
274	  planStyleValue?: string;
275	  onPlanStyleChange?: (id: string) => void;
276	}): JSX.Element {
277	  const { t } = useTranslation();
278	  const showSelects =
279	    (perspectiveOptions && perspectiveOptions.length > 0) ||
280	    (planStyleOptions && planStyleOptions.length > 0);
281	  return (
282	    <div className="flex items-center gap-1.5">
283	      {showSelects ? (
284	        <>
285	          {perspectiveOptions &&
286	          perspectiveOptions.length > 0 &&
287	          perspectiveValue !== undefined &&
288	          onPerspectiveChange ? (
289	            <TopBarSelect
290	              value={perspectiveValue}
291	              onChange={onPerspectiveChange}
292	              options={perspectiveOptions}
293	              label={t('topbar.perspective')}
294	            />
295	          ) : null}
296	          {planStyleOptions &&
297	          planStyleOptions.length > 0 &&
298	          planStyleValue !== undefined &&
299	          onPlanStyleChange ? (
300	            <TopBarSelect
301	              value={planStyleValue}
302	              onChange={onPlanStyleChange}
303	              options={planStyleOptions}
304	              label={t('topbar.planStyle')}
305	            />
306	          ) : null}
307	          <div className="mx-1 h-4 w-px bg-border" aria-hidden="true" />
308	        </>
309	      ) : null}
310	      <button
311	        type="button"
312	        onClick={onCommandPalette}
313	        aria-label={IconLabels.commandPalette}
314	        aria-keyshortcuts="Meta+K Control+K"
315	        className="flex items-center gap-1.5 rounded-md border border-border bg-surface px-2.5 py-1 text-xs font-medium text-muted shadow-sm hover:bg-surface-strong hover:text-foreground"
316	      >
317	        <Icons.commandPalette size={13} aria-hidden="true" />
318	        <span className="tabular-nums">⌘K</span>
319	      </button>
320	      {peers && peers.length > 0 ? (
321	        <>
322	          <div className="mx-0.5 h-4 w-px bg-border" aria-hidden="true" />
323	          <div
324	            data-testid="peer-avatars"
325	            className="flex items-center -space-x-1"
326	            aria-label={t('topbar.activeCollaborators')}
327	          >
328	            {peers.slice(0, 5).map((p, i) => (
329	              <div
330	                key={i}
331	                title={p.name ?? t('topbar.anonymous')}
332	                className="flex h-6 w-6 items-center justify-center rounded-full border-2 border-surface text-[9px] font-semibold text-foreground ring-0"
333	                style={{ backgroundColor: p.color ?? 'var(--color-surface-strong)', zIndex: 5 - i }}
334	              >
335	                {(p.name ?? '?').slice(0, 2).toUpperCase()}
336	              </div>
337	            ))}
338	          </div>
339	        </>
340	      ) : null}
341	      <IconButton
342	        Icon={Icons.collaborators}
343	        label={IconLabels.collaborators}
344	        onClick={onCollaboratorsClick}
345	        badge={collaboratorsCount}
346	      />
347	      <IconButton Icon={Icons.settings} label={IconLabels.settings} onClick={onSettings} />
348	      <IconButton
349	        Icon={theme === 'dark' ? Icons.themeLight : Icons.themeDark}
350	        label={theme === 'dark' ? IconLabels.themeLight : IconLabels.themeDark}
351	        onClick={onThemeToggle}
352	        data-testid="topbar-theme-toggle"
353	        data-current-theme={theme}
354	      />
355	      <div className="mx-0.5 h-4 w-px bg-border" aria-hidden="true" />
356	      <div
357	        aria-label={t('topbar.account')}
358	        title={avatarInitials ?? ''}
359	        className="flex h-7 w-7 items-center justify-center rounded-full border border-border bg-accent/15 text-[11px] font-semibold text-accent"
360	      >
361	        {(avatarInitials ?? '··').slice(0, 2).toUpperCase()}
362	      </div>
363	    </div>
364	  );
365	}
366	
367	function TopBarSelect({
368	  value,
369	  onChange,
370	  options,
371	  label,
372	}: {
373	  value: string;
374	  onChange: (v: string) => void;
375	  options: TopBarSelectOption[];
376	  label: string;
377	}): JSX.Element {
378	  return (
379	    <div className="relative flex items-center">
380	      <select
381	        aria-label={label}
382	        title={label}
383	        value={value}
384	        onChange={(e) => onChange(e.target.value)}
385	        className="h-7 cursor-pointer appearance-none rounded-md border border-border bg-surface pl-2.5 pr-6 text-xs font-medium text-foreground shadow-sm transition-colors hover:bg-surface-strong focus:outline-none focus:ring-1 focus:ring-accent"
386	      >
387	        {options.map((o) => (
388	          <option key={o.id} value={o.id}>
389	            {o.label}
390	          </option>
391	        ))}
392	      </select>
393	      <Icons.disclosureOpen
394	        size={11}
395	        className="pointer-events-none absolute right-1.5 text-muted"
396	        aria-hidden="true"
397	      />
398	    </div>
399	  );
400	}
401	
402	interface IconButtonProps {
403	  Icon: LucideLikeIcon;
404	  label: string;
405	  onClick?: (e: MouseEvent<HTMLButtonElement>) => void;
406	  badge?: number;
407	  ['data-testid']?: string;
408	  ['data-current-theme']?: string;
409	}
410	
411	function IconButton({
412	  Icon,
413	  label,
414	  onClick,
415	  badge,
416	  'data-testid': testId,
417	  'data-current-theme': currentTheme,
418	}: IconButtonProps): JSX.Element {
419	  const handleFocus = useCallback((_e: FocusEvent<HTMLButtonElement>) => {
420	    /* no-op — declared so consumers can extend later. */
421	  }, []);
422	
423	  return (
424	    <button
425	      type="button"
426	      onClick={onClick}
427	      onFocus={handleFocus}
428	      aria-label={label}
429	      title={label}
430	      data-testid={testId}
431	      data-current-theme={currentTheme}
432	      className="relative inline-flex h-8 w-8 items-center justify-center rounded-md text-muted transition-colors hover:bg-surface hover:text-foreground"
433	    >
434	      <Icon size={ICON_SIZE.topbar} aria-hidden="true" />
435	      {typeof badge === 'number' && badge > 0 ? (
436	        <span
437	          data-testid="topbar-badge"
438	          aria-hidden="true"
439	          className="absolute -right-0.5 -top-0.5 inline-flex h-4 min-w-4 items-center justify-center rounded-pill bg-accent px-1 text-xs text-accent-foreground"
440	        >
441	          {badge}
442	        </span>
443	      ) : null}
444	    </button>
445	  );
446	}
