import React, { useCallback, useEffect, useState } from 'react';

interface PresentationRecord {
  id: string;
  modelId: string;
  token: string;
  createdBy: string;
  createdAt: number;
  expiresAt?: number;
  isRevoked: boolean;
  openCount: number;
}

interface PageOption {
  id: string;
  name: string;
}

interface Props {
  modelId: string;
  open: boolean;
  onClose: () => void;
  pages?: PageOption[];
}

export function SharePresentationModal({ modelId, open, onClose, pages = [] }: Props) {
  const [presentations, setPresentations] = useState<PresentationRecord[]>([]);
  const [selectedPageIds, setSelectedPageIds] = useState<string[]>([]);
  const [allPages, setAllPages] = useState(true);
  const [allowMeasurement, setAllowMeasurement] = useState(false);
  const [allowComment, setAllowComment] = useState(false);
  const [expiry, setExpiry] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copiedToken, setCopiedToken] = useState<string | null>(null);

  const fetchPresentations = useCallback(async () => {
    try {
      const res = await fetch(`/api/models/${modelId}/presentations`);
      if (!res.ok) return;
      const data = await res.json();
      setPresentations(data.presentations ?? []);
    } catch {
      // silently ignore
    }
  }, [modelId]);

  useEffect(() => {
    if (open) {
      fetchPresentations();
      setError(null);
    }
  }, [open, fetchPresentations]);

  const handlePageToggle = useCallback((pageId: string) => {
    setSelectedPageIds((prev) =>
      prev.includes(pageId) ? prev.filter((id) => id !== pageId) : [...prev, pageId],
    );
  }, []);

  const handleAllPagesToggle = useCallback(() => {
    setAllPages((prev) => !prev);
    setSelectedPageIds([]);
  }, []);

  const handleCopyLink = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const pageScopeIds = allPages ? [] : selectedPageIds;
      const body: Record<string, unknown> = {
        pageScopeIds,
        allowMeasurement,
        allowComment,
      };
      if (expiry) body.expiresAt = new Date(expiry).getTime();

      const res = await fetch(`/api/models/${modelId}/presentations`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        setError((data as { detail?: string }).detail ?? 'Failed to create presentation');
        return;
      }
      const data = await res.json();
      const url = `${window.location.origin}/p/${data.token}`;
      await navigator.clipboard.writeText(url);
      setCopiedToken(data.token);
      setTimeout(() => setCopiedToken(null), 2000);
      await fetchPresentations();
    } finally {
      setLoading(false);
    }
  }, [modelId, allPages, selectedPageIds, allowMeasurement, allowComment, expiry, fetchPresentations]);

  const handleRevoke = useCallback(
    async (linkId: string) => {
      setLoading(true);
      setError(null);
      try {
        await fetch(`/api/models/${modelId}/presentations/${linkId}/revoke`, { method: 'POST' });
        await fetchPresentations();
      } finally {
        setLoading(false);
      }
    },
