import React, { useCallback, useEffect, useState } from 'react';

interface PresentationRecord {
  id: string;
  modelId: string;
  token: string;
  createdBy: string;
  createdAt: number;
  expiresAt?: number;
  isRevoked: boolean;
  openCount: number;
