            Share live presentation
          </strong>
          <button
            onClick={onClose}
            aria-label="Close share presentation modal"
            style={{ border: 'none', background: 'none', cursor: 'pointer', color: 'var(--color-muted-foreground)' }}
          >
            ✕
          </button>
        </div>

        {error && (
          <div
            style={{
