                gap: 8,
                fontSize: 'var(--text-sm)',
                color: 'var(--color-foreground)',
                marginBottom: 6,
              }}
            >
              <input
                type="checkbox"
                checked={allPages}
                onChange={handleAllPagesToggle}
              />
              All pages
            </label>
            {!allPages &&
              pages.map((page) => (
                <label
                  key={page.id}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                    fontSize: 'var(--text-sm)',
                    color: 'var(--color-muted-foreground)',
                    marginBottom: 4,
                    paddingLeft: 20,
                  }}
                >
                  <input
                    type="checkbox"
