            .catch(() => {});
        }
      } catch {
        // ignore malformed messages
      }
    };

    ws.onclose = (event) => {
      if (event.code === 4403) {
        setRevoked(true);
      }
    };

    return () => {
      ws.close();
      wsRef.current = null;
    };
  }, [data?.wsUrl, token]);

  if (loading) {
    return (
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100vh',
          color: 'var(--color-muted-foreground)',
          fontSize: 'var(--text-sm)',
        }}
      >
        Loading presentation…
      </div>
    );
  }

  if (revoked) {
    return (
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100vh',
          gap: 12,
          color: 'var(--color-muted-foreground)',
        }}
      >
        <span style={{ fontSize: 32 }}>🔒</span>
        <p style={{ fontSize: 18, fontWeight: 600, color: 'var(--color-foreground)', margin: 0 }}>
          Presentation revoked
        </p>
        <p style={{ fontSize: 'var(--text-sm)', margin: 0 }}>
          This presentation link is no longer active.
        </p>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden' }}>
      <PresentationBanner displayName={data?.presentation?.displayName} />
      <div
        style={{
          flex: 1,
          marginTop: 32,
          position: 'relative',
          background: 'var(--color-surface)',
        }}
      >
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            height: '100%',
            color: 'var(--color-muted-foreground)',
            fontSize: 'var(--text-sm)',
          }}
        >
          {data
            ? `Viewing model ${data.modelId} — revision ${data.revision}`
            : 'No presentation data'}
        </div>
      </div>
    </div>
  );
}

function PresentationBanner({ displayName }: { displayName?: string }) {
  return (
    <div
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        height: 32,
        background: 'var(--color-surface-2)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '0 16px',
        fontSize: 'var(--text-sm)',
        zIndex: 100,
        borderBottom: '1px solid var(--color-border)',
      }}
    >
      <span style={{ color: 'var(--color-foreground)' }}>
        {displayName ? `Shared by ${displayName}` : 'Live presentation (read-only)'}
      </span>
      <a
        href="/login"
        style={{
          color: 'var(--color-accent)',
          textDecoration: 'none',
          fontSize: 'var(--text-sm)',
        }}
      >
        Sign in to edit →
      </a>
    </div>
  );
}

