import React, { useEffect, useRef, useState } from 'react';

interface PresentationMeta {
  id: string;
  displayName?: string;
  openCount: number;
}

interface PresentationData {
  status: 'ok' | 'revoked';
  modelId?: string;
  revision?: number;
  elements?: Record<string, unknown>;
  wsUrl?: string;
  presentation?: PresentationMeta;
  allowMeasurement?: boolean;
  allowComment?: boolean;
}

interface Props {
  token: string;
}

export function PresentationViewer({ token }: Props) {
  const [data, setData] = useState<PresentationData | null>(null);
  const [revoked, setRevoked] = useState(false);
  const [loading, setLoading] = useState(true);
  const wsRef = useRef<WebSocket | null>(null);

  useEffect(() => {
    let cancelled = false;

    async function load() {
      setLoading(true);
      try {
        const res = await fetch(`/api/p/${token}`);
        if (!res.ok) {
          setRevoked(true);
          return;
        }
        const json: PresentationData = await res.json();
        if (cancelled) return;
        if (json.status === 'revoked') {
          setRevoked(true);
          return;
        }
        setData(json);
      } catch {
        if (!cancelled) setRevoked(true);
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    load();
    return () => {
      cancelled = true;
    };
  }, [token]);

  useEffect(() => {
    if (!data?.wsUrl) return;

