import React, { useCallback, useEffect, useState } from 'react';

interface PresentationRecord {
  id: string;
  modelId: string;
  token: string;
  createdBy: string;
  createdAt: number;
  expiresAt?: number;
  isRevoked: boolean;
  openCount: number;
}

interface PageOption {
  id: string;
  name: string;
}

interface Props {
  modelId: string;
  open: boolean;
  onClose: () => void;
  pages?: PageOption[];
}

export function SharePresentationModal({ modelId, open, onClose, pages = [] }: Props) {
  const [presentations, setPresentations] = useState<PresentationRecord[]>([]);
  const [selectedPageIds, setSelectedPageIds] = useState<string[]>([]);
  const [allPages, setAllPages] = useState(true);
  const [allowMeasurement, setAllowMeasurement] = useState(false);
  const [allowComment, setAllowComment] = useState(false);
  const [expiry, setExpiry] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copiedToken, setCopiedToken] = useState<string | null>(null);

  const fetchPresentations = useCallback(async () => {
    try {
      const res = await fetch(`/api/models/${modelId}/presentations`);
      if (!res.ok) return;
      const data = await res.json();
      setPresentations(data.presentations ?? []);
    } catch {
      // silently ignore
    }
  }, [modelId]);

  useEffect(() => {
    if (open) {
      fetchPresentations();
      setError(null);
    }
  }, [open, fetchPresentations]);

  const handlePageToggle = useCallback((pageId: string) => {
    setSelectedPageIds((prev) =>
      prev.includes(pageId) ? prev.filter((id) => id !== pageId) : [...prev, pageId],
    );
  }, []);

  const handleAllPagesToggle = useCallback(() => {
    setAllPages((prev) => !prev);
    setSelectedPageIds([]);
  }, []);

  const handleCopyLink = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const pageScopeIds = allPages ? [] : selectedPageIds;
      const body: Record<string, unknown> = {
        pageScopeIds,
        allowMeasurement,
        allowComment,
      };
      if (expiry) body.expiresAt = new Date(expiry).getTime();

      const res = await fetch(`/api/models/${modelId}/presentations`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        setError((data as { detail?: string }).detail ?? 'Failed to create presentation');
        return;
      }
      const data = await res.json();
      const url = `${window.location.origin}/p/${data.token}`;
      await navigator.clipboard.writeText(url);
      setCopiedToken(data.token);
      setTimeout(() => setCopiedToken(null), 2000);
      await fetchPresentations();
    } finally {
      setLoading(false);
    }
  }, [
    modelId,
    allPages,
    selectedPageIds,
    allowMeasurement,
    allowComment,
    expiry,
    fetchPresentations,
  ]);

  const handleRevoke = useCallback(
    async (linkId: string) => {
      setLoading(true);
      setError(null);
      try {
        await fetch(`/api/models/${modelId}/presentations/${linkId}/revoke`, {
          method: 'POST',
        });
        await fetchPresentations();
      } finally {
        setLoading(false);
      }
    },
    [modelId, fetchPresentations],
  );

  if (!open) return null;

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label="Share live presentation"
      style={{
        position: 'fixed',
        inset: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'rgba(0,0,0,0.4)',
        zIndex: 1000,
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        style={{
          background: 'var(--color-surface-2)',
          borderRadius: 8,
          width: 520,
          maxWidth: '90vw',
          maxHeight: '85vh',
          overflowY: 'auto',
          padding: '24px',
          boxShadow: '0 8px 32px rgba(0,0,0,0.24)',
          border: '1px solid var(--color-border)',
        }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
          <strong style={{ fontSize: 16, color: 'var(--color-foreground)' }}>
            Share live presentation
          </strong>
          <button
            onClick={onClose}
            aria-label="Close share presentation modal"
            style={{
              border: 'none',
              background: 'none',
              cursor: 'pointer',
              color: 'var(--color-muted-foreground)',
            }}
          >
            ✕
          </button>
        </div>

        {error && (
          <div
            style={{
              color: 'var(--color-destructive)',
              marginBottom: 12,
              fontSize: 'var(--text-sm)',
            }}
          >
            {error}
          </div>
        )}

        {pages.length > 0 && (
          <section style={{ marginBottom: 20 }}>
            <p
              style={{
                fontSize: 'var(--text-sm)',
                fontWeight: 600,
                color: 'var(--color-foreground)',
                marginBottom: 8,
              }}
            >
              Scope
            </p>
            <label
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                fontSize: 'var(--text-sm)',
                color: 'var(--color-foreground)',
                marginBottom: 6,
              }}
            >
              <input type="checkbox" checked={allPages} onChange={handleAllPagesToggle} />
              All pages
            </label>
            {!allPages &&
              pages.map((page) => (
                <label
                  key={page.id}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                    fontSize: 'var(--text-sm)',
                    color: 'var(--color-muted-foreground)',
                    marginBottom: 4,
                    paddingLeft: 20,
                  }}
                >
                  <input
                    type="checkbox"
                    checked={selectedPageIds.includes(page.id)}
                    onChange={() => handlePageToggle(page.id)}
                  />
                  {page.name}
                </label>
              ))}
          </section>
        )}

        <section style={{ marginBottom: 20 }}>
          <p
            style={{
              fontSize: 'var(--text-sm)',
              fontWeight: 600,
              color: 'var(--color-foreground)',
              marginBottom: 8,
            }}
          >
            Viewer permissions
          </p>
          <label
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              fontSize: 'var(--text-sm)',
              color: 'var(--color-foreground)',
              marginBottom: 6,
            }}
          >
            <input
              type="checkbox"
              checked={allowMeasurement}
              onChange={(e) => setAllowMeasurement(e.target.checked)}
            />
            Allow measurement
          </label>
          <label
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              fontSize: 'var(--text-sm)',
              color: 'var(--color-foreground)',
            }}
          >
            <input
              type="checkbox"
              checked={allowComment}
              onChange={(e) => setAllowComment(e.target.checked)}
            />
            Allow comment
          </label>
        </section>

        <section style={{ marginBottom: 20 }}>
          <label style={{ fontSize: 'var(--text-sm)', color: 'var(--color-foreground)' }}>
            Expiry (optional)
            <input
              type="datetime-local"
              value={expiry}
              onChange={(e) => setExpiry(e.target.value)}
              style={{
                display: 'block',
                marginTop: 4,
                padding: '8px 10px',
                borderRadius: 4,
                border: '1px solid var(--color-border)',
                fontSize: 'var(--text-sm)',
                width: '100%',
                background: 'var(--color-surface)',
                color: 'var(--color-foreground)',
              }}
            />
          </label>
        </section>

        <button
          onClick={handleCopyLink}
          disabled={loading}
          style={{
            width: '100%',
            padding: '10px 16px',
            borderRadius: 4,
            background: 'var(--color-accent)',
            color: 'var(--color-accent-foreground)',
            border: 'none',
            cursor: loading ? 'not-allowed' : 'pointer',
            fontSize: 'var(--text-sm)',
            fontWeight: 600,
            marginBottom: 24,
          }}
        >
          {copiedToken ? 'Copied!' : loading ? 'Creating…' : 'Copy link'}
        </button>

        {presentations.length > 0 && (
          <section>
            <p
              style={{
                fontSize: 'var(--text-sm)',
                fontWeight: 600,
                color: 'var(--color-foreground)',
                marginBottom: 12,
              }}
            >
              Active presentations
            </p>
            {presentations.map((p) => (
              <div
                key={p.id}
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  padding: '8px 0',
                  borderBottom: '1px solid var(--color-border)',
                }}
              >
                <div>
                  <span style={{ fontSize: 'var(--text-sm)', color: 'var(--color-foreground)' }}>
                    {new Date(p.createdAt).toLocaleDateString()}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--text-sm)',
                      color: 'var(--color-muted-foreground)',
                      marginLeft: 8,
                    }}
                  >
                    {p.openCount} view{p.openCount !== 1 ? 's' : ''}
                  </span>
                </div>
                <button
                  onClick={() => handleRevoke(p.id)}
                  disabled={loading}
                  style={{
                    fontSize: 'var(--text-sm)',
                    color: 'var(--color-destructive)',
                    border: 'none',
                    background: 'none',
                    cursor: 'pointer',
                    padding: '4px 8px',
                  }}
                >
                  Revoke
                </button>
              </div>
            ))}
          </section>
        )}
      </div>
    </div>
  );
}

import React, { useEffect, useRef, useState } from 'react';

interface PresentationMeta {
  id: string;
  displayName?: string;
  openCount: number;
}

interface PresentationData {
  status: 'ok' | 'revoked';
  modelId?: string;
  revision?: number;
  elements?: Record<string, unknown>;
  wsUrl?: string;
  presentation?: PresentationMeta;
  allowMeasurement?: boolean;
  allowComment?: boolean;
}

interface Props {
  token: string;
}

export function PresentationViewer({ token }: Props) {
  const [data, setData] = useState<PresentationData | null>(null);
  const [revoked, setRevoked] = useState(false);
  const [loading, setLoading] = useState(true);
  const wsRef = useRef<WebSocket | null>(null);

  useEffect(() => {
    let cancelled = false;

    async function load() {
      setLoading(true);
      try {
        const res = await fetch(`/api/p/${token}`);
        if (!res.ok) {
          setRevoked(true);
          return;
        }
        const json: PresentationData = await res.json();
        if (cancelled) return;
        if (json.status === 'revoked') {
          setRevoked(true);
          return;
        }
        setData(json);
      } catch {
        if (!cancelled) setRevoked(true);
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    load();
    return () => {
      cancelled = true;
    };
  }, [token]);

  useEffect(() => {
    if (!data?.wsUrl) return;

    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = `${protocol}//${window.location.host}${data.wsUrl}`;
    const ws = new WebSocket(wsUrl);
    wsRef.current = ws;

    ws.onmessage = (event) => {
      try {
        const msg = JSON.parse(event.data as string) as { type: string };
        if (msg.type === 'revoked') {
          setRevoked(true);
          ws.close();
        } else if (msg.type === 'snapshot_update' || msg.type === 'delta') {
          fetch(`/api/p/${token}`)
            .then((r) => r.json())
            .then((updated: PresentationData) => {
              if (updated.status !== 'revoked') {
                setData((prev) => ({ ...prev, ...updated }));
              } else {
                setRevoked(true);
              }
            })
            .catch(() => {});
        }
      } catch {
        // ignore malformed messages
      }
    };

    ws.onclose = (event) => {
      if (event.code === 4403) {
        setRevoked(true);
      }
    };

    return () => {
      ws.close();
      wsRef.current = null;
    };
  }, [data?.wsUrl, token]);

  if (loading) {
    return (
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100vh',
          color: 'var(--color-muted-foreground)',
          fontSize: 'var(--text-sm)',
        }}
      >
        Loading presentation…
      </div>
    );
  }

  if (revoked) {
    return (
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100vh',
          gap: 12,
          color: 'var(--color-muted-foreground)',
        }}
      >
        <p style={{ fontSize: 18, fontWeight: 600, color: 'var(--color-foreground)', margin: 0 }}>
          Presentation revoked
        </p>
        <p style={{ fontSize: 'var(--text-sm)', margin: 0 }}>
          This presentation link is no longer active.
        </p>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden' }}>
      <PresentationBanner displayName={data?.presentation?.displayName} />
      <div
        style={{
          flex: 1,
          marginTop: 32,
          position: 'relative',
          background: 'var(--color-surface)',
        }}
      >
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            height: '100%',
            color: 'var(--color-muted-foreground)',
            fontSize: 'var(--text-sm)',
          }}
        >
          {data
            ? `Viewing model ${data.modelId} — revision ${data.revision}`
            : 'No presentation data'}
        </div>
      </div>
    </div>
  );
}

function PresentationBanner({ displayName }: { displayName?: string }) {
  return (
    <div
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        height: 32,
        background: 'var(--color-surface-2)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '0 16px',
        fontSize: 'var(--text-sm)',
        zIndex: 100,
        borderBottom: '1px solid var(--color-border)',
      }}
    >
      <span style={{ color: 'var(--color-foreground)' }}>
        {displayName ? `Shared by ${displayName}` : 'Live presentation (read-only)'}
      </span>
      <a
        href="/login"
        style={{
          color: 'var(--color-accent)',
          textDecoration: 'none',
          fontSize: 'var(--text-sm)',
        }}
      >
        Sign in to edit →
      </a>
    </div>
  );
}

import {
  type CSSProperties,
  type FocusEvent,
  type JSX,
  type KeyboardEvent,
  type MouseEvent,
  useCallback,
  useId,
  useRef,
} from 'react';
import { useTranslation } from 'react-i18next';
import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';

/**
 * TopBar — spec §11.
 *
 * Three regions:
 *   1. Left  (240 px): hamburger toggle, logo placeholder, project-name button.
 *   2. Center: mode pills traversable with arrow keys (`role="tablist"`).
 *   3. Right: command palette button, collaborators count, settings, theme
 *      toggle, avatar.
 *
 * The TopBar is purely presentational. State (current mode, theme,
 * collaborators) is owned by callers (Workspace + Mode-switching WP-D03).
 */

export const WORKSPACE_MODES = [
  { id: 'plan', label: 'Plan', hotkey: '1' },
  { id: '3d', label: '3D', hotkey: '2' },
  { id: 'plan-3d', label: 'Plan + 3D', hotkey: '3' },
  { id: 'section', label: 'Section', hotkey: '4' },
  { id: 'sheet', label: 'Sheet', hotkey: '5' },
  { id: 'schedule', label: 'Schedule', hotkey: '6' },
  { id: 'agent', label: 'Agent', hotkey: '7' },
] as const;

export type WorkspaceMode = (typeof WORKSPACE_MODES)[number]['id'];

export interface TopBarSelectOption {
  id: string;
  label: string;
}

export interface TopBarProps {
  mode: WorkspaceMode;
  onModeChange: (next: WorkspaceMode) => void;
  projectName: string;
  onProjectNameClick?: () => void;
  /** Forwarded to the project-name pill so external popovers can anchor. */
  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
  onHamburgerClick?: () => void;
  theme: 'light' | 'dark';
  onThemeToggle?: () => void;
  onCommandPalette?: () => void;
  onSettings?: () => void;
  collaboratorsCount?: number;
  onCollaboratorsClick?: () => void;
  /** Identifier shown as the avatar fallback when no avatar URL is provided. */
  avatarInitials?: string;
  /** Presence peers to render as avatar chips (up to 6). */
  peers?: Array<{ name?: string; color?: string }>;
  /** Discipline/perspective filter selector. */
  perspectiveOptions?: TopBarSelectOption[];
  perspectiveValue?: string;
  onPerspectiveChange?: (id: string) => void;
  /** Plan presentation style selector. */
  planStyleOptions?: TopBarSelectOption[];
  planStyleValue?: string;
  onPlanStyleChange?: (id: string) => void;
  /** OUT-V3-01: true when at least one Page exists in the model. */
  hasPages?: boolean;
  /** OUT-V3-01: callback to open the SharePresentationModal. */
  onSharePresentation?: () => void;
}

export function TopBar({
  mode,
  onModeChange,
  projectName,
  onProjectNameClick,
  projectNameRef,
  onHamburgerClick,
  theme,
  onThemeToggle,
  onCommandPalette,
  onSettings,
  collaboratorsCount,
  onCollaboratorsClick,
  avatarInitials,
  peers,
  perspectiveOptions,
  perspectiveValue,
  onPerspectiveChange,
  planStyleOptions,
  planStyleValue,
  onPlanStyleChange,
  hasPages,
  onSharePresentation,
}: TopBarProps): JSX.Element {
  const tablistId = useId();
  return (
    <div
      data-testid="topbar"
      role="banner"
      style={topBarStyle}
      className="flex w-full items-center gap-4 border-b border-border bg-background px-4"
    >
      <TopBarLeft
        projectName={projectName}
        onProjectNameClick={onProjectNameClick}
        projectNameRef={projectNameRef}
        onHamburgerClick={onHamburgerClick}
      />
      <TopBarModePills tablistId={tablistId} mode={mode} onModeChange={onModeChange} />
      <TopBarRight
        theme={theme}
        onThemeToggle={onThemeToggle}
        onCommandPalette={onCommandPalette}
        onSettings={onSettings}
        collaboratorsCount={collaboratorsCount}
        onCollaboratorsClick={onCollaboratorsClick}
        avatarInitials={avatarInitials}
        peers={peers}
        perspectiveOptions={perspectiveOptions}
        perspectiveValue={perspectiveValue}
        onPerspectiveChange={onPerspectiveChange}
        planStyleOptions={planStyleOptions}
        planStyleValue={planStyleValue}
        onPlanStyleChange={onPlanStyleChange}
        hasPages={hasPages}
        onSharePresentation={onSharePresentation}
      />
    </div>
  );
}

const topBarStyle: CSSProperties = {
  height: 'var(--shell-topbar-height)',
  minHeight: 'var(--shell-topbar-height)',
};

function TopBarLeft({
  projectName,
  onProjectNameClick,
  projectNameRef,
  onHamburgerClick,
}: {
  projectName: string;
  onProjectNameClick?: () => void;
  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
  onHamburgerClick?: () => void;
}): JSX.Element {
  const { t } = useTranslation();
  return (
    <div className="flex items-center gap-3" style={{ minWidth: 240 }}>
      <IconButton Icon={Icons.hamburger} label={IconLabels.hamburger} onClick={onHamburgerClick} />
      <div
        aria-label={t('topbar.appLogoAriaLabel')}
        className="flex h-6 w-6 items-center justify-center rounded bg-accent text-accent-foreground"
        style={{ fontWeight: 700, fontSize: 11, letterSpacing: '0.01em' }}
      >
        BA
      </div>
      <button
        type="button"
        ref={projectNameRef}
        onClick={onProjectNameClick}
        className="flex items-center gap-1.5 rounded-md px-2 py-1 text-sm font-semibold text-foreground hover:bg-surface"
        aria-haspopup="menu"
        data-testid="topbar-project-name"
      >
        <span className="truncate" style={{ maxWidth: 160 }}>
          {projectName}
        </span>
        <Icons.disclosureOpen size={14} className="text-muted" aria-hidden="true" />
      </button>
    </div>
  );
}

function TopBarModePills({
  tablistId,
  mode,
  onModeChange,
}: {
  tablistId: string;
  mode: WorkspaceMode;
  onModeChange: (next: WorkspaceMode) => void;
}): JSX.Element {
  const { t } = useTranslation();
  const tabRefs = useRef<Map<WorkspaceMode, HTMLButtonElement>>(new Map());
  const setTabRef = useCallback(
    (id: WorkspaceMode) => (el: HTMLButtonElement | null) => {
      if (el) tabRefs.current.set(id, el);
      else tabRefs.current.delete(id);
    },
    [],
  );

  const handleKey = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
      const idx = WORKSPACE_MODES.findIndex((m) => m.id === mode);
      if (idx < 0) return;
      const delta = event.key === 'ArrowRight' ? 1 : -1;
      const next = WORKSPACE_MODES[(idx + delta + WORKSPACE_MODES.length) % WORKSPACE_MODES.length];
      event.preventDefault();
      onModeChange(next.id);
      tabRefs.current.get(next.id)?.focus();
    },
    [mode, onModeChange],
  );

  return (
    <div
      role="tablist"
      id={tablistId}
      aria-label={t('topbar.modesAriaLabel')}
      onKeyDown={handleKey}
      className="flex flex-1 items-center justify-center gap-1"
    >
      {WORKSPACE_MODES.map((m) => {
        const active = m.id === mode;
        const modeLabel = t(`topbar.modes.${m.id}`);
        return (
          <button
            key={m.id}
            ref={setTabRef(m.id)}
            type="button"
            role="tab"
            aria-selected={active}
            aria-keyshortcuts={m.hotkey}
            tabIndex={active ? 0 : -1}
            onClick={() => onModeChange(m.id)}
            data-active={active ? 'true' : 'false'}
            title={`${modeLabel} (${m.hotkey})`}
            className={[
              'relative rounded px-3 py-1.5 text-sm font-medium transition-colors',
              active ? 'text-accent' : 'text-muted hover:bg-surface hover:text-foreground',
            ].join(' ')}
            style={active ? { boxShadow: 'inset 0 -2px 0 0 var(--color-accent)' } : undefined}
          >
            {modeLabel}
            <span aria-hidden="true" className="ml-1.5 text-[10px] tabular-nums opacity-40">
              {m.hotkey}
            </span>
          </button>
        );
      })}
    </div>
  );
}

function TopBarRight({
  theme,
  onThemeToggle,
  onCommandPalette,
  onSettings,
  collaboratorsCount,
  onCollaboratorsClick,
  avatarInitials,
  peers,
  perspectiveOptions,
  perspectiveValue,
  onPerspectiveChange,
  planStyleOptions,
  planStyleValue,
  onPlanStyleChange,
  hasPages,
  onSharePresentation,
}: {
  theme: 'light' | 'dark';
  onThemeToggle?: () => void;
  onCommandPalette?: () => void;
  onSettings?: () => void;
  collaboratorsCount?: number;
  onCollaboratorsClick?: () => void;
  avatarInitials?: string;
  peers?: Array<{ name?: string; color?: string }>;
  perspectiveOptions?: TopBarSelectOption[];
  perspectiveValue?: string;
  onPerspectiveChange?: (id: string) => void;
  planStyleOptions?: TopBarSelectOption[];
  planStyleValue?: string;
  onPlanStyleChange?: (id: string) => void;
  hasPages?: boolean;
  onSharePresentation?: () => void;
}): JSX.Element {
  const { t } = useTranslation();
  const showSelects =
    (perspectiveOptions && perspectiveOptions.length > 0) ||
    (planStyleOptions && planStyleOptions.length > 0);
  return (
    <div className="flex items-center gap-1.5">
      {showSelects ? (
        <>
          {perspectiveOptions &&
          perspectiveOptions.length > 0 &&
          perspectiveValue !== undefined &&
          onPerspectiveChange ? (
            <TopBarSelect
              value={perspectiveValue}
              onChange={onPerspectiveChange}
              options={perspectiveOptions}
              label={t('topbar.perspective')}
            />
          ) : null}
          {planStyleOptions &&
          planStyleOptions.length > 0 &&
          planStyleValue !== undefined &&
          onPlanStyleChange ? (
            <TopBarSelect
              value={planStyleValue}
              onChange={onPlanStyleChange}
              options={planStyleOptions}
              label={t('topbar.planStyle')}
            />
          ) : null}
          <div className="mx-1 h-4 w-px bg-border" aria-hidden="true" />
        </>
      ) : null}
      <button
        type="button"
        onClick={hasPages ? onSharePresentation : undefined}
        disabled={!hasPages}
        aria-label="Share live presentation"
        title={hasPages ? 'Share live presentation' : 'Add a Page first'}
        style={{ background: 'var(--color-surface-2)' }}
        className="flex items-center gap-1.5 rounded-md border border-border px-2.5 py-1 text-muted shadow-sm hover:bg-surface-strong hover:text-foreground disabled:cursor-not-allowed disabled:opacity-40"
      >
        <span style={{ fontSize: 'var(--text-sm)' }}>Share live presentation</span>
      </button>
      <button
        type="button"
        onClick={onCommandPalette}
        aria-label={IconLabels.commandPalette}
        aria-keyshortcuts="Meta+K Control+K"
        className="flex items-center gap-1.5 rounded-md border border-border bg-surface px-2.5 py-1 text-xs font-medium text-muted shadow-sm hover:bg-surface-strong hover:text-foreground"
      >
        <Icons.commandPalette size={13} aria-hidden="true" />
        <span className="tabular-nums">⌘K</span>
      </button>
      {peers && peers.length > 0 ? (
        <>
          <div className="mx-0.5 h-4 w-px bg-border" aria-hidden="true" />
          <div
            data-testid="peer-avatars"
            className="flex items-center -space-x-1"
            aria-label={t('topbar.activeCollaborators')}
          >
            {peers.slice(0, 5).map((p, i) => (
              <div
                key={i}
                title={p.name ?? t('topbar.anonymous')}
                className="flex h-6 w-6 items-center justify-center rounded-full border-2 border-surface text-[9px] font-semibold text-foreground ring-0"
                style={{ backgroundColor: p.color ?? 'var(--color-surface-strong)', zIndex: 5 - i }}
              >
                {(p.name ?? '?').slice(0, 2).toUpperCase()}
              </div>
            ))}
          </div>
        </>
      ) : null}
      <IconButton
        Icon={Icons.collaborators}
        label={IconLabels.collaborators}
        onClick={onCollaboratorsClick}
        badge={collaboratorsCount}
      />
      <IconButton Icon={Icons.settings} label={IconLabels.settings} onClick={onSettings} />
      <IconButton
        Icon={theme === 'dark' ? Icons.themeLight : Icons.themeDark}
        label={theme === 'dark' ? IconLabels.themeLight : IconLabels.themeDark}
        onClick={onThemeToggle}
        data-testid="topbar-theme-toggle"
        data-current-theme={theme}
      />
      <div className="mx-0.5 h-4 w-px bg-border" aria-hidden="true" />
      <div
        aria-label={t('topbar.account')}
        title={avatarInitials ?? ''}
        className="flex h-7 w-7 items-center justify-center rounded-full border border-border bg-accent/15 text-[11px] font-semibold text-accent"
      >
        {(avatarInitials ?? '··').slice(0, 2).toUpperCase()}
      </div>
    </div>
  );
}

function TopBarSelect({
  value,
  onChange,
  options,
  label,
}: {
  value: string;
  onChange: (v: string) => void;
  options: TopBarSelectOption[];
  label: string;
}): JSX.Element {
  return (
    <div className="relative flex items-center">
      <select
        aria-label={label}
        title={label}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="h-7 cursor-pointer appearance-none rounded-md border border-border bg-surface pl-2.5 pr-6 text-xs font-medium text-foreground shadow-sm transition-colors hover:bg-surface-strong focus:outline-none focus:ring-1 focus:ring-accent"
      >
        {options.map((o) => (
          <option key={o.id} value={o.id}>
            {o.label}
          </option>
        ))}
      </select>
      <Icons.disclosureOpen
        size={11}
        className="pointer-events-none absolute right-1.5 text-muted"
        aria-hidden="true"
      />
    </div>
  );
}

interface IconButtonProps {
  Icon: LucideLikeIcon;
  label: string;
  onClick?: (e: MouseEvent<HTMLButtonElement>) => void;
  badge?: number;
  ['data-testid']?: string;
  ['data-current-theme']?: string;
}

function IconButton({
  Icon,
  label,
  onClick,
  badge,
  'data-testid': testId,
  'data-current-theme': currentTheme,
}: IconButtonProps): JSX.Element {
  const handleFocus = useCallback((_e: FocusEvent<HTMLButtonElement>) => {
    /* no-op — declared so consumers can extend later. */
  }, []);

  return (
    <button
      type="button"
      onClick={onClick}
      onFocus={handleFocus}
      aria-label={label}
      title={label}
      data-testid={testId}
      data-current-theme={currentTheme}
      className="relative inline-flex h-8 w-8 items-center justify-center rounded-md text-muted transition-colors hover:bg-surface hover:text-foreground"
    >
      <Icon size={ICON_SIZE.topbar} aria-hidden="true" />
      {typeof badge === 'number' && badge > 0 ? (
        <span
          data-testid="topbar-badge"
          aria-hidden="true"
          className="absolute -right-0.5 -top-0.5 inline-flex h-4 min-w-4 items-center justify-center rounded-pill bg-accent px-1 text-xs text-accent-foreground"
        >
          {badge}
        </span>
      ) : null}
    </button>
  );
}

